/** Look up blur placeholder for a background ID (e.g. "bg_showroom"). */
export function getBackgroundBlur(bgId: string): string | undefined {
  return BLUR_HASHES[`backgrounds/${bgId}`];
}

/** Look up blur placeholder for a character sprite path. */
export function getCharacterBlur(assetPath: string): string | undefined {
  // assetPath: /assets/scenarios/car-dealership/characters/chr_rustam_friendly.webp
  const match = assetPath.match(/characters\/(.+?)\.[^.]+$/);
  if (!match) return undefined;
  return BLUR_HASHES[`characters/${match[1]}`];
}
